function toFolderNode(item) {
  if (!item || typeof item !== 'object') return null;
  const folderId = item.id ?? item.folderTreeId ?? item.folderId;
  if (folderId == null) return null;
  const name = item.name ?? item.folderName ?? ('folder_' + folderId);
  let parentId = item.parentId;
  if (parentId == null && item.parent && typeof item.parent === 'object') {
    parentId = item.parent.id;
  }
  const fullPath = item.fullName ?? item.path ?? '';
  return {
    folder_id: String(folderId),
    folder_name: String(name),
    parent_id: parentId != null ? String(parentId) : null,
    full_path: String(fullPath || ''),
    is_leaf: false
  };
}

function collectFolderNodes(payload) {
  const collected = [];
  function walk(p) {
    if (p == null) return;
    if (Array.isArray(p)) {
      for (const e of p) walk(e);
      return;
    }
    if (typeof p === 'object') {
      const n = toFolderNode(p);
      if (n) collected.push(n);
      for (const key of ['values', 'results', 'items', 'content', 'folders', 'children', 'data', 'result']) {
        const v = p[key];
        if (Array.isArray(v)) {
          for (const e of v) walk(e);
        } else if (v && typeof v === 'object') {
          walk(v);
        }
      }
    }
  }
  walk(payload);
  return collected;
}

