const raw = items[0].json || {};
const payload = raw.error ? {} : raw;
const nodes = collectFolderNodes(payload);
return [{ json: { nodes, folder_discovery: nodes.length ? 'foldertree' : 'none' } }];

const cfg = $items('Build_Config', 0, 0)[0].json;
const rawNodes = (items[0].json && items[0].json.nodes) ? items[0].json.nodes : [];
if (!rawNodes.length) {
  return [];
}
const byId = {};
for (const n of rawNodes) {
  byId[n.folder_id] = { ...n };
}
const nodes = Object.values(byId);
const childrenByParent = {};
for (const n of nodes) {
  const p = n.parent_id || '';
  if (!childrenByParent[p]) childrenByParent[p] = [];
  childrenByParent[p].push(n.folder_id);
}
const cache = {};
function buildPath(folderId) {
  if (cache[folderId] !== undefined) return cache[folderId];
  const node = byId[folderId];
  if (!node) {
    cache[folderId] = '';
    return '';
  }
  const fp = (node.full_path || '').trim();
  if (fp) {
    cache[folderId] = fp;
    return fp;
  }
  if (node.parent_id && byId[node.parent_id]) {
    const pp = buildPath(node.parent_id);
    const path = (pp ? pp + '/' : '') + node.folder_name;
    cache[folderId] = path.replace(/\/+/g, '/').replace(/^\/+/, '');
    return cache[folderId];
  }
  cache[folderId] = node.folder_name;
  return cache[folderId];
}
for (const n of nodes) {
  if (!(n.full_path || '').trim()) {
    n.full_path = buildPath(n.folder_id);
  }
}
for (const n of nodes) {
  const kids = childrenByParent[n.folder_id] || [];
  n.is_leaf = kids.length === 0;
}
const rootIds = String(cfg.folderRootIds || '').split(',').map((s) => s.trim()).filter(Boolean);
let allowed = null;
if (rootIds.length) {
  allowed = new Set();
  const stack = [...rootIds];
  while (stack.length) {
    const id = stack.pop();
    if (allowed.has(id)) continue;
    allowed.add(id);
    const kids = childrenByParent[id] || [];
    for (const k of kids) stack.push(k);
  }
}
const leafOnly = cfg.folderLeafOnly === true || cfg.folderLeafOnly === 'true';
let nameRe = null;
if (cfg.folderNameRegex && String(cfg.folderNameRegex).trim()) {
  try { nameRe = new RegExp(cfg.folderNameRegex); } catch (e) { nameRe = null; }
}
let pathRe = null;
if (cfg.folderPathRegex && String(cfg.folderPathRegex).trim()) {
  try { pathRe = new RegExp(cfg.folderPathRegex); } catch (e) { pathRe = null; }
}
const now = new Date().toISOString();
const out = [];
for (const n of nodes) {
  if (allowed && !allowed.has(n.folder_id)) continue;
  if (leafOnly && !n.is_leaf) continue;
  if (nameRe && !nameRe.test(n.folder_name)) continue;
  if (pathRe && !pathRe.test(n.full_path || '')) continue;
  out.push({
    json: {
      folder_id: n.folder_id,
      folder_name: n.folder_name,
      folder_path: n.full_path || '',
      is_active: true,
      last_ingested_at: now
    }
  });
}
return out;

const esc = (value) => {
  if (value === null || value === undefined) return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
if (!items.length) {
  return [{ json: { sql_query: 'SELECT 1 AS zephyr_ingest_folders_noop;' } }];
}
const vals = items.map((item) => {
  const r = item.json;
  return '(' + esc(r.folder_id) + ', ' + esc(r.folder_name) + ', ' + esc(r.folder_path) + ', true, ' + esc(r.last_ingested_at) + '::timestamptz)';
}).join(',\n');
const sql = 'INSERT INTO folders (folder_id, folder_name, folder_path, is_active, last_ingested_at)\nVALUES ' + vals + '\nON CONFLICT (folder_id) DO UPDATE SET\n  folder_name = EXCLUDED.folder_name,\n  folder_path = EXCLUDED.folder_path,\n  is_active = EXCLUDED.is_active,\n  last_ingested_at = EXCLUDED.last_ingested_at;';
return [{ json: { sql_query: sql, row_count: items.length } }];

function sanitizeTql(q) {
  let cleaned = String(q || '').trim();
  if ((cleaned.startsWith("'") && cleaned.endsWith("'")) || (cleaned.startsWith('"') && cleaned.endsWith('"'))) {
    cleaned = cleaned.slice(1, -1).trim();
  }
  const re = /\bORDER\s+BY\b/gi;
  const matches = [...cleaned.matchAll(re)];
  if (matches.length > 1) {
    cleaned = cleaned.slice(0, matches[1].index).trim();
  }
  return cleaned;
}

function buildQueryString(params) {
  return Object.entries(params)
    .filter(([, value]) => value !== undefined && value !== null && String(value) !== '')
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
    .join('&');
}

const cfg = $items('Build_Config', 0, 0)[0].json;
const base = String(cfg.baseUrl || '').replace(/\/+$/, '');
const endpoint = String(cfg.testrunSearchEndpoint || 'rest/tests/1.0/testrun/search').replace(/^\/+/, '');
const template = cfg.queryTemplate || 'testRun.projectId IN ({project_id}) AND testRun.folderTreeId IN ({folder_id}) ORDER BY testRun.name ASC';
const fields = String(cfg.testrunFields || '').trim();
const maxResults = String(cfg.maxResults ?? '100');
const startAt = String(cfg.startAt ?? '0');
const archived = String(cfg.archived ?? 'false');
const projectId = String(cfg.projectId || '');

return items.map((item) => {
  const folderId = String(item.json.folder_id || '');
  let q = String(template)
    .split('{project_id}').join(projectId)
    .split('{folder_id}').join(folderId);
  q = sanitizeTql(q);
  const params = { query: q, maxResults, startAt, archived };
  if (fields) {
    params.fields = fields;
  }
  const qs = buildQueryString(params);
  return {
    json: {
      folder_id: folderId,
      request_url: base + '/' + endpoint + '?' + qs,
    },
  };
});

function getByPath(obj, path) {
  let cur = obj;
  for (const p of path.split('.')) {
    if (!cur || typeof cur !== 'object') return null;
    cur = cur[p];
  }
  return cur;
}

function readField(row, paths, fallback) {
  const fb = fallback === undefined ? '' : fallback;
  for (const path of paths) {
    if (path.indexOf('.') !== -1) {
      const v = getByPath(row, path);
      if (v != null && v !== '') return String(v);
    } else if (row[path] != null && row[path] !== '') {
      return String(row[path]);
    }
  }
  return fb;
}

const reqItems = $items('Build_Testrun_Request_Items', 0, 0);
const now = new Date().toISOString();
const out = [];

for (let i = 0; i < items.length; i++) {
  const http = items[i].json || {};
  const folderId = (reqItems[i] && reqItems[i].json) ? String(reqItems[i].json.folder_id || '') : '';
  const payload = http.error ? {} : http;
  const list = payload.values || payload.results || payload.executions || payload.items || [];
  if (!Array.isArray(list)) continue;
  for (const cycle of list) {
    if (!cycle || typeof cycle !== 'object') continue;
    const testRunId = readField(cycle, ['id', 'testRunId'], '');
    if (!testRunId) continue;
    const execRaw = readField(cycle, ['updatedOn', 'executedOn', 'executionDate'], '');
    let execDay = execRaw ? execRaw.slice(0, 10) : null;
    if (execDay === '') execDay = null;
    out.push({
      json: {
        test_run_id: testRunId,
        folder_id: folderId,
        cycle_id: readField(cycle, ['iterationId', 'iteration.id'], ''),
        run_name: readField(cycle, ['iteration.name', 'testRunName', 'name'], ''),
        execution_day: execDay,
        source_status_name: readField(cycle, ['status.name', 'status', 'result'], ''),
        last_ingested_at: now,
      },
    });
  }
}

return out;

const esc = (value) => {
  if (value === null || value === undefined) return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const escDate = (value) => {
  if (!value || String(value).trim() === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'::date";
};

const byId = new Map();
for (const item of items) {
  const r = item.json;
  if (r.test_run_id) byId.set(String(r.test_run_id), r);
}
const rows = Array.from(byId.values());
if (!rows.length) {
  return [{ json: { sql_query: 'SELECT 1 AS zephyr_ingest_testruns_noop;' } }];
}

const vals = rows.map((r) => {
  return '(' + esc(r.test_run_id) + ', ' + esc(r.folder_id) + ', ' + esc(r.cycle_id || '') + ', ' + esc(r.run_name || '') + ', ' + escDate(r.execution_day) + ', ' + esc(r.source_status_name || '') + ', ' + esc(r.last_ingested_at) + '::timestamptz)';
}).join(',\n');

const sql = 'INSERT INTO test_runs (test_run_id, folder_id, cycle_id, run_name, execution_day, source_status_name, last_ingested_at)\nVALUES ' + vals + '\nON CONFLICT (test_run_id) DO UPDATE SET\n  folder_id = EXCLUDED.folder_id,\n  cycle_id = EXCLUDED.cycle_id,\n  run_name = EXCLUDED.run_name,\n  execution_day = EXCLUDED.execution_day,\n  source_status_name = EXCLUDED.source_status_name,\n  last_ingested_at = EXCLUDED.last_ingested_at;';

return [{ json: { sql_query: sql, row_count: rows.length } }];

function buildQueryString(params) {
  return Object.entries(params)
    .filter(([, value]) => value !== undefined && value !== null && String(value) !== '')
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
    .join('&');
}

const cfg = $items('Build_Config', 0, 0)[0].json;
const base = String(cfg.baseUrl || '').replace(/\/+$/, '');
const endpointTemplate = String(cfg.testresultEndpointTemplate || 'rest/tests/1.0/testrun/{test_run_id}/testrunitems');
const fields = String(cfg.testresultFields || '').trim();

return items.map((item) => {
  const runId = String(item.json.test_run_id || '');
  const endpoint = endpointTemplate.split('{test_run_id}').join(runId).replace(/^\/+/, '');
  const params = {};
  if (fields) {
    params.fields = fields;
  }
  const qs = buildQueryString(params);
  return {
    json: {
      test_run_id: runId,
      request_url: base + '/' + endpoint + (qs ? '?' + qs : ''),
    },
  };
});

function getByPath(obj, path) {
  let cur = obj;
  for (const p of path.split('.')) {
    if (!cur || typeof cur !== 'object') return null;
    cur = cur[p];
  }
  return cur;
}

function readField(row, paths, fallback) {
  const fb = fallback === undefined ? '' : fallback;
  for (const path of paths) {
    if (path.indexOf('.') !== -1) {
      const v = getByPath(row, path);
      if (v != null && v !== '') return String(v);
    } else if (row[path] != null && row[path] !== '') {
      return String(row[path]);
    }
  }
  return fb;
}

const reqItems = $items('Build_Testresult_Request_Items', 0, 0);
const statusItems = $items('Fetch_Testresult_Statuses', 0, 0);
const statusMap = {};
for (const sItem of statusItems) {
  const payload = sItem.json;
  const list = Array.isArray(payload)
    ? payload
    : (payload && Array.isArray(payload.values)
      ? payload.values
      : (payload && typeof payload === 'object' && payload.id != null ? [payload] : []));
  for (const s of list) {
    if (!s || typeof s !== 'object') continue;
    const sid = s.id;
    const sname = s.name;
    if (sid != null && sname) {
      statusMap[String(sid)] = String(sname);
    }
  }
}

const now = new Date().toISOString();
const out = [];

for (let i = 0; i < items.length; i++) {
  const http = items[i].json || {};
  const runId = (reqItems[i] && reqItems[i].json) ? String(reqItems[i].json.test_run_id || '') : '';
  const payload = http.error ? {} : http;

  let list = [];
  if (Array.isArray(payload)) {
    list = payload;
  } else {
    list = payload.testRunItems || payload.values || payload.results || payload.items || payload.content || payload.testResults || [];
  }
  if (!Array.isArray(list)) continue;

  for (const row of list) {
    if (!row || typeof row !== 'object') continue;
    const lastResult = (row.$lastTestResult && typeof row.$lastTestResult === 'object') ? row.$lastTestResult : row;
    const testResultId = readField(lastResult, ['id', 'testResultId'], '');
    if (!testResultId) continue;
    const statusId = readField(lastResult, ['testResultStatusId'], '');
    const statusNameRaw = readField(lastResult, ['status.name', 'testResultStatus.name', 'status', 'result'], '');
    const statusFromRawMap = statusNameRaw ? (statusMap[statusNameRaw] || '') : '';
    const statusNameMapped = statusId ? (statusMap[statusId] || '') : '';
    const statusName = statusFromRawMap || statusNameMapped || statusNameRaw || statusId;
    out.push({
      json: {
        test_result_id: testResultId,
        test_run_id: runId,
        test_case_key: readField(lastResult, ['testCase.key', 'testCaseKey'], ''),
        test_case_name: readField(lastResult, ['testCase.name', 'testCaseName', 'name'], ''),
        current_status_name: statusName,
        updated_at: now,
      },
    });
  }
}

return out;

